import{a as e,c as t,i as n,n as r,o as i,r as a,s as o}from"./app-Bq6_fEfR.js";import{t as s}from"./plugin-vue_export-helper-C2MVdOIS.js";var c=JSON.parse(`{"path":"/claudecode/Claude%20Code%20%E6%9D%83%E9%99%90%E6%A8%A1%E5%BC%8F.html","title":"Claude Code 权限模式完全指南","lang":"zh-CN","frontmatter":{"description":"Claude Code 权限模式完全指南 一、权限模式总览 Claude Code 权限模式用于控制 AI 在执行文件读写、代码编辑、Shell 命令、网络请求等操作时是否需要用户确认，在安全可控与自动化效率之间做分级平衡，支持会话中切换、启动指定、默认配置三种生效方式，适配从敏感开发到自动化任务的全场景。 Claude Code 权限模式决策流程如下...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Claude Code 权限模式完全指南\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-05-04T07:53:13.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/claudecode/Claude%20Code%20%E6%9D%83%E9%99%90%E6%A8%A1%E5%BC%8F.html"}],["meta",{"property":"og:site_name","content":"小林学AI"}],["meta",{"property":"og:title","content":"Claude Code 权限模式完全指南"}],["meta",{"property":"og:description","content":"Claude Code 权限模式完全指南 一、权限模式总览 Claude Code 权限模式用于控制 AI 在执行文件读写、代码编辑、Shell 命令、网络请求等操作时是否需要用户确认，在安全可控与自动化效率之间做分级平衡，支持会话中切换、启动指定、默认配置三种生效方式，适配从敏感开发到自动化任务的全场景。 Claude Code 权限模式决策流程如下..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-05-04T07:53:13.000Z"}],["meta",{"property":"article:modified_time","content":"2026-05-04T07:53:13.000Z"}]]},"git":{"createdTime":1777881193000,"updatedTime":1777881193000,"contributors":[{"name":"Yideng","username":"Yideng","email":"oointer@163.com","commits":1,"url":"https://github.com/Yideng"}]},"readingTime":{"minutes":6.65,"words":1995},"filePathRelative":"claudecode/Claude Code 权限模式.md","autoDesc":true}`),l={name:`Claude Code 权限模式.md`};function u(s,c,l,u,d,f){let p=t(`Mermaid`);return o(),a(`div`,null,[c[0]||=r(`h1`,{id:`claude-code-权限模式完全指南`,tabindex:`-1`},[r(`a`,{class:`header-anchor`,href:`#claude-code-权限模式完全指南`},[r(`span`,null,`Claude Code 权限模式完全指南`)])],-1),c[1]||=r(`h2`,{id:`一、权限模式总览`,tabindex:`-1`},[r(`a`,{class:`header-anchor`,href:`#一、权限模式总览`},[r(`span`,null,`一、权限模式总览`)])],-1),c[2]||=r(`p`,null,[e(`Claude Code 权限模式用于控制 AI 在执行文件读写、代码编辑、Shell 命令、网络请求等操作时是否需要用户确认，在`),r(`strong`,null,`安全可控`),e(`与`),r(`strong`,null,`自动化效率`),e(`之间做分级平衡，支持会话中切换、启动指定、默认配置三种生效方式，适配从敏感开发到自动化任务的全场景。`)],-1),c[3]||=r(`p`,null,`Claude Code 权限模式决策流程如下：`,-1),i(p,{code:``}),c[4]||=n(`<p>官方提供 6 种标准模式：<strong>default、acceptEdits、plan、auto、dontAsk、bypassPermissions</strong>，覆盖从强管控到全自动化的完整梯度，所有模式可通过 CLI、IDE 插件、桌面端、Web 端统一切换与配置。</p><h2 id="二、权限模式切换与配置" tabindex="-1"><a class="header-anchor" href="#二、权限模式切换与配置"><span>二、权限模式切换与配置</span></a></h2><h3 id="_2-1-会话内快速切换" tabindex="-1"><a class="header-anchor" href="#_2-1-会话内快速切换"><span>2.1 会话内快速切换</span></a></h3><ul><li>CLI / JetBrains：<strong>Shift+Tab</strong> 循环切换 default → acceptEdits → plan → auto（需先启用）；bypassPermissions 需启动参数开启。</li><li>VS Code / Desktop / Web：使用界面模式选择器，UI 标签与配置键一一映射，便于可视化操作。</li></ul><h3 id="_2-2-启动指定模式" tabindex="-1"><a class="header-anchor" href="#_2-2-启动指定模式"><span>2.2 启动指定模式</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="shiki" data-ext="bash" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-bash"><span class="line"><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;"># 启动为规划模式</span></span>
<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">claude</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --permission-mode</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> plan</span></span>
<span class="line"><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;"># 非交互式脚本执行</span></span>
<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">claude</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> -p</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> &quot;重构代码&quot;</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --permission-mode</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> acceptEdits</span></span>
<span class="line"><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;"># 启用 Auto 模式</span></span>
<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">claude</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --enable-auto-mode</span></span>
<span class="line"><span style="--shiki-light:#A0A1A7;--shiki-light-font-style:italic;--shiki-dark:#7F848E;--shiki-dark-font-style:italic;"># 跳过所有权限检查（高危）</span></span>
<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">claude</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --dangerously-skip-permissions</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-3-设置默认模式" tabindex="-1"><a class="header-anchor" href="#_2-3-设置默认模式"><span>2.3 设置默认模式</span></a></h3><p>在 <code>.claude/settings.json</code> 中配置全局默认权限模式，持久生效：</p><div class="language-json line-numbers-mode" data-highlighter="shiki" data-ext="json" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code class="language-json"><span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">{</span></span>
<span class="line"><span style="--shiki-light:#E45649;--shiki-dark:#E06C75;">  &quot;permissions&quot;</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">: {</span></span>
<span class="line"><span style="--shiki-light:#E45649;--shiki-dark:#E06C75;">    &quot;defaultMode&quot;</span><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">: </span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;">&quot;acceptEdits&quot;</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">  }</span></span>
<span class="line"><span style="--shiki-light:#383A42;--shiki-dark:#ABB2BF;">}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三、6-种权限模式详解与选型" tabindex="-1"><a class="header-anchor" href="#三、6-种权限模式详解与选型"><span>三、6 种权限模式详解与选型</span></a></h2><h3 id="_3-1-default-默认询问模式" tabindex="-1"><a class="header-anchor" href="#_3-1-default-默认询问模式"><span>3.1 default（默认询问模式）</span></a></h3><ul><li>权限行为：仅<strong>读取文件</strong>自动允许；文件编辑、Shell 命令、网络请求均需用户手动确认。</li><li>核心优势：每一步操作都在监督下，安全性最高，避免误执行高危指令。</li><li>适用场景：首次接触项目、敏感业务开发、生产环境附近操作、不信任代码场景。</li></ul><h3 id="_3-2-acceptedits-自动接受编辑" tabindex="-1"><a class="header-anchor" href="#_3-2-acceptedits-自动接受编辑"><span>3.2 acceptEdits（自动接受编辑）</span></a></h3><ul><li>权限行为：自动允许<strong>读取 + 编辑文件</strong>；仅 Shell 命令、网络等高风险操作需确认。</li><li>核心优势：大幅减少确认弹窗，兼顾编辑效率与命令安全，是日常开发首选。</li><li>适用场景：熟悉项目、迭代开发、代码重构，信任 AI 编辑但严控命令执行。</li></ul><h3 id="_3-3-plan-只读规划模式" tabindex="-1"><a class="header-anchor" href="#_3-3-plan-只读规划模式"><span>3.3 plan（只读规划模式）</span></a></h3><ul><li>权限行为：<strong>禁止任何修改执行</strong>，仅允许读取、分析、生成方案，输出计划文件。</li><li>核心优势：先调研后动手，不污染源码，适合复杂任务前置设计。</li><li>适用场景：多文件重构、架构调整、代码库探索、需求分析，可通过 <code>/plan</code> 单请求启用。</li></ul><h3 id="_3-4-auto-自动模式-带安全分类器" tabindex="-1"><a class="header-anchor" href="#_3-4-auto-自动模式-带安全分类器"><span>3.4 auto（自动模式，带安全分类器）</span></a></h3><ul><li>权限行为：无人工弹窗，由后台分类器自动审查操作，拦截越权、高危、恶意指令。</li><li>核心约束：需 Team/Enterprise 套餐、Sonnet 4.6+/Opus 4.6+ 模型；分类器会临时禁用通配符 Bash 规则等高风险权限。</li><li>默认阻止：curl|bash 类远程执行、生产部署、大规模删除、强制推送 main 分支、泄露敏感数据等高危行为。</li><li>适用场景：长时间自动化任务、批量重构、减少提示疲劳，信任任务方向但需安全兜底。</li></ul><h3 id="_3-5-dontask-仅允许预授权工具" tabindex="-1"><a class="header-anchor" href="#_3-5-dontask-仅允许预授权工具"><span>3.5 dontAsk（仅允许预授权工具）</span></a></h3><ul><li>权限行为：<strong>自动拒绝所有未显式允许</strong>的操作，无任何交互弹窗，纯非交互模式。</li><li>核心逻辑：只执行 permissions.allow 里白名单明确许可的工具/命令，完全可控。</li><li>适用场景：CI/CD 流水线、受限环境、自动化脚本、批量任务，杜绝越权执行。</li></ul><h3 id="_3-6-bypasspermissions-跳过所有检查-高危" tabindex="-1"><a class="header-anchor" href="#_3-6-bypasspermissions-跳过所有检查-高危"><span>3.6 bypassPermissions（跳过所有检查，高危）</span></a></h3><ul><li>权限行为：关闭所有权限提示与安全检查，<strong>所有操作立即执行</strong>，无任何验证。</li><li>风险提示：无防注入、无防误操作保护，官方明确仅用于隔离容器/VM/无网开发环境。</li><li>禁用方式：管理员可在托管配置中强制关闭此模式，防止滥用。</li><li>适用场景：完全隔离的沙箱、实验环境、本地测试虚拟机，严禁用于生产相关环境。</li></ul><h2 id="四、权限模式对比与选型指南" tabindex="-1"><a class="header-anchor" href="#四、权限模式对比与选型指南"><span>四、权限模式对比与选型指南</span></a></h2><table><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">权限提示</th><th style="text-align:left;">安全检查</th><th style="text-align:left;">自动化程度</th><th style="text-align:left;">最佳场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>default</strong></td><td style="text-align:left;">文件编辑+命令</td><td style="text-align:left;">人工逐次确认</td><td style="text-align:left;">低</td><td style="text-align:left;">陌生项目、敏感开发</td></tr><tr><td style="text-align:left;"><strong>acceptEdits</strong></td><td style="text-align:left;">仅命令</td><td style="text-align:left;">人工审核命令</td><td style="text-align:left;">中</td><td style="text-align:left;">日常迭代、信任项目</td></tr><tr><td style="text-align:left;"><strong>plan</strong></td><td style="text-align:left;">所有操作（只读）</td><td style="text-align:left;">人工全量审核</td><td style="text-align:left;">极低</td><td style="text-align:left;">规划重构、探索代码</td></tr><tr><td style="text-align:left;"><strong>auto</strong></td><td style="text-align:left;">无（触发回退除外）</td><td style="text-align:left;">AI 分类器审查</td><td style="text-align:left;">高</td><td style="text-align:left;">长时任务、批量处理</td></tr><tr><td style="text-align:left;"><strong>dontAsk</strong></td><td style="text-align:left;">无</td><td style="text-align:left;">预配置白名单</td><td style="text-align:left;">中高</td><td style="text-align:left;">CI/CD、受限环境</td></tr><tr><td style="text-align:left;"><strong>bypassPermissions</strong></td><td style="text-align:left;">无</td><td style="text-align:left;">无</td><td style="text-align:left;">极高</td><td style="text-align:left;">隔离沙箱、实验环境</td></tr></tbody></table><h3 id="选型建议" tabindex="-1"><a class="header-anchor" href="#选型建议"><span>选型建议</span></a></h3><ul><li>个人开发：优先 <strong>acceptEdits</strong>，平衡效率与安全。</li><li>敏感/生产相关：固定 <strong>default</strong> 或 <strong>plan</strong>，全程人工把关。</li><li>长时间自动化：用 <strong>auto</strong>，比 bypassPermissions 更安全。</li><li>流水线/脚本：用 <strong>dontAsk</strong>，白名单严格管控。</li><li>沙箱实验：仅在此场景使用 <strong>bypassPermissions</strong>。</li></ul><h2 id="五、auto-模式安全机制与回退规则" tabindex="-1"><a class="header-anchor" href="#五、auto-模式安全机制与回退规则"><span>五、Auto 模式安全机制与回退规则</span></a></h2><h3 id="_5-1-分类器审查逻辑" tabindex="-1"><a class="header-anchor" href="#_5-1-分类器审查逻辑"><span>5.1 分类器审查逻辑</span></a></h3><ol><li>优先匹配用户自定义 allow/deny 规则。</li><li>只读与本地文件编辑自动批准。</li><li>其余操作送入分类器，基于上下文意图判断安全性。</li><li>阻止后会尝试替代方案，不直接中断会话。</li></ol><h3 id="_5-2-回退保护机制" tabindex="-1"><a class="header-anchor" href="#_5-2-回退保护机制"><span>5.2 回退保护机制</span></a></h3><ul><li>连续阻止 3 次 或 会话累计阻止 20 次 → 自动退出 auto，切回手动确认模式。</li><li>非交互式会话触发回退则直接中止，保障安全。</li></ul><h3 id="_5-3-子代理安全约束" tabindex="-1"><a class="header-anchor" href="#_5-3-子代理安全约束"><span>5.3 子代理安全约束</span></a></h3><ul><li>子代理启动前分类器审查任务描述。</li><li>运行中继承父会话权限与分类器规则。</li><li>执行结束后全量审计操作历史，异常追加安全警告。</li></ul><h2 id="六、权限扩展与安全加固" tabindex="-1"><a class="header-anchor" href="#六、权限扩展与安全加固"><span>六、权限扩展与安全加固</span></a></h2><h3 id="_6-1-权限规则-优先级高于模式" tabindex="-1"><a class="header-anchor" href="#_6-1-权限规则-优先级高于模式"><span>6.1 权限规则（优先级高于模式）</span></a></h3><p>在 settings.json 中配置 allow/ask/deny 规则，精细化管控工具与命令，覆盖所有模式（bypassPermissions 除外）：</p><ul><li>示例：允许 npm test、拒绝 rm -rf、强制询问部署命令。</li></ul><h3 id="_6-2-hooks-高级控制" tabindex="-1"><a class="header-anchor" href="#_6-2-hooks-高级控制"><span>6.2 Hooks 高级控制</span></a></h3><ul><li>PreToolUse：工具调用前执行自定义校验，按路径、命令、策略服务动态允许/拒绝/升级。</li><li>PermissionRequest：自动应答权限请求，实现无人值守合规审批。</li></ul><h3 id="_6-3-企业安全管控" tabindex="-1"><a class="header-anchor" href="#_6-3-企业安全管控"><span>6.3 企业安全管控</span></a></h3><ul><li>托管配置 managed-settings.json 优先级最高，可禁用 bypassPermissions、限制 Auto 模式、白名单受信任仓库与云服务。</li><li>审计分类器默认规则：<code>claude auto-mode defaults</code>。</li><li>配置信任环境：通过 autoMode.environment 声明可信仓库、存储桶、内部服务，减少误拦。</li></ul><h2 id="七、常见问题与最佳实践" tabindex="-1"><a class="header-anchor" href="#七、常见问题与最佳实践"><span>七、常见问题与最佳实践</span></a></h2><ol><li>模式切换不生效：检查是否被托管配置覆盖，CLI 确认参数传入正确，IDE 重启插件。</li><li>Auto 模式频繁阻止：补充信任基础设施配置，或改用 acceptEdits 人工审核命令。</li><li>权限弹窗过多：日常开发切到 acceptEdits，批量任务用 auto，脚本用 dontAsk。</li><li>安全底线：任何生产相关操作不使用 bypassPermissions；敏感文件与凭证通过权限规则禁止读取；定期清理会话记录，降低泄露风险。</li></ol><h2 id="八、总结" tabindex="-1"><a class="header-anchor" href="#八、总结"><span>八、总结</span></a></h2><p>Claude Code 权限模式提供<strong>从强管控到全自动化</strong>的完整安全梯度，核心是按场景匹配风险等级：日常用 acceptEdits、敏感用 default/plan、自动化用 auto、流水线用 dontAsk、沙箱用 bypassPermissions。配合权限规则、Hooks、企业托管配置，可构建安全、高效、合规的 AI 辅助开发环境，在提升效率的同时严格控制操作风险。</p>`,45)])}var d=s(l,[[`render`,u]]);export{c as _pageData,d as default};